import{_ as e,c as i,a,o as n}from"./app-CEcM0piI.js";const l={};function d(t,s){return n(),i("div",null,s[0]||(s[0]=[a(`<p>Nuxt框架提供了一种基于Node.js的服务端渲染方案SSR（Server Side Rendering），可以让Vue应用在服务器端进行染，从而提高页面的加载速度和SEO。I</p><p><strong>SPA和SSR是什么</strong></p><ul><li>SPA（SinglePageApplication）单页面应用，在客户端通过JS动态地构建页面。</li><li>SSR（Server-SideRendering）服务器端渲染，在服务器端生成HTML页面并发送给客户端。</li></ul><p><strong>Nuxt框架优势</strong></p><ul><li>Nuxt采用了混合的架构模式，同时支持SSR和SPA。</li><li>SSR服务端渲染：首次访问页面，Nuxt.js在服务器端执行Vue组件的渲染过程，并生成初始HTML</li><li>SPA客户端激活：一旦初始HTML被发送到浏览器，Vue.js会接管页面，后续的页面切换则使用SPA的方式进行。</li><li>Nuxt框架优势：兼顾了SSR和SPA的优点。</li></ul><h1 id="配置" tabindex="-1"><a class="header-anchor" href="#配置"><span>配置</span></a></h1><ul><li>开发工具</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  devtools: { enabled: true },</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>开发服务器配置</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  devServer: {</span></span>
<span class="line"><span>    port: 3000,</span></span>
<span class="line"><span>  },</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>源码映射</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  sourcemap: {</span></span>
<span class="line"><span>    server: true,</span></span>
<span class="line"><span>    client: true,</span></span>
<span class="line"><span>  },</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>导入的模块</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  modules: [&quot;@element-plus/nuxt&quot;],</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><ul><li>运行时配置</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>  runtimeConfig: {</span></span>
<span class="line"><span>    isServer: true,</span></span>
<span class="line"><span>    public: {</span></span>
<span class="line"><span>      apiBase: process.env.NUXT_API_BASE,</span></span>
<span class="line"><span>    },</span></span>
<span class="line"><span>  },</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>public属性下的是客户端和服务端都可以获取的，isServer或者isClient是只有服务端或只有客户端才可以获取。如果获取的不是自己有权访问的得到的结构是undefined 在获取时从全局对象<code>config</code>中获取</p><h1 id="路由" tabindex="-1"><a class="header-anchor" href="#路由"><span>路由</span></a></h1><p>在nuxt中不需要使用vue-router，它是基于文件的路由系统</p><p>跳转时使用<code>NuxtLink</code>组件，显示路由页面使用<code>NuxtPage</code>组件</p><p>nuxt会检查当前项目根目录中的<strong>pages</strong>文件夹，根据其中的文件夹设置路由，并且路由名是pages文件夹下的子文件夹名字，跳转页面是子目录中的index.vue文件</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>├── pages/                     //页面目录</span></span>
<span class="line"><span>|    ├── index/ </span></span>
<span class="line"><span>│    |   └── index.vue         //主页</span></span>
<span class="line"><span>|    └── video/ </span></span>
<span class="line"><span>         └── video.vue         //视频页</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>默认生效条件如下：页面名必须是pages、子目录中必须包含index文件、pages文件夹必须在根目录中等。 如果有不同的需求也可以更改配置</p><h2 id="路由传参" tabindex="-1"><a class="header-anchor" href="#路由传参"><span>路由传参</span></a></h2><p>文件命名时将页面命名为带<code>[]</code>的文件，其中的变量就是路由传参的变量名 如：<code>pages/posts/[id].vue</code></p><div class="language-pages/posts/ line-numbers-mode" data-highlighter="shiki" data-ext="pages/posts/" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;script setup lang=&quot;ts&quot;&gt;</span></span>
<span class="line"><span>const route = useRoute()</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 当访问 /posts/1 时，route.params.id 将为 1</span></span>
<span class="line"><span>console.log(route.params.id)</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果动态路由页面同级目录下有其他的页面文件则先精准匹配其他的页面路由，最后再匹配动态路由</p><h1 id="seo优化" tabindex="-1"><a class="header-anchor" href="#seo优化"><span>SEO优化</span></a></h1><p>使用Nuxt最主要的是实现SEO优化，可以被搜索引擎搜索到 要使用seo优化需要在App.vue中做设置</p><ul><li>title：在搜索引擎中显示的标题</li><li>description：标题下的描述</li><li>keywords：搜索关键字</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;script setup lang=&quot;ts&quot;&gt;</span></span>
<span class="line"><span>useSeoMeta({</span></span>
<span class="line"><span>  title: &quot;哔哩哔哩 (゜-゜)つロ 干杯~-bilibili&quot;,</span></span>
<span class="line"><span>  description:</span></span>
<span class="line"><span>    &quot;哔哩哔哩（bilibili.com)是国内知名的视频弹幕网站。&quot;,</span></span>
<span class="line"><span>  keywords:</span></span>
<span class="line"><span>    &quot;B站,哔哩哔哩,bilibili,弹幕网,弹幕视频,弹幕网站,动漫,电影&quot;</span></span>
<span class="line"><span>});</span></span>
<span class="line"><span>&lt;/script&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="接口请求" tabindex="-1"><a class="header-anchor" href="#接口请求"><span>接口请求</span></a></h1><p>在nuxt项目中可以设置后端接口 需要在特定文件夹下</p><p>接口文件需要放在根目录的server文件夹中，请求路径就是<code>nuxt服务器地址+端口号+/server文件夹中的文件夹+/文件名</code><code>server/api/user.ts</code>文件请求的接口就是<code>localhost:3000/api/user</code>，默认是所有请求都可以识别的，但也可以更改文件名设置只接收某种请求，如：<code>user.get.ts</code>文件只能被get请求识别</p><p>返回后端数据需要使用defineEventHandler函数，为这个函数传入一个函数，返回值就是要返回的数据</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>export default defineEventHandler(()=&gt;{</span></span>
<span class="line"><span>	return data</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="发送请求" tabindex="-1"><a class="header-anchor" href="#发送请求"><span>发送请求</span></a></h2><p>nuxt有封装好的请求函数，不需要使用axios</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const res=await useFetch(&#39;/api/user&#39;)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h1 id="状态共享" tabindex="-1"><a class="header-anchor" href="#状态共享"><span>状态共享</span></a></h1><p>对于服务端渲染的代码，需要辨别当前运行环境是服务端还是客户端， 判断当前文件是客户端还是服务端使用<code>import.meta</code> 如果在服务端渲染的代码中设置了修改了变量，而这段代码在服务端和客户端都会运行通常会运行两次，默认的情况下客户端和服务端是属性隔离的</p><p>如果以下代码在服务端和客户端都有执行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const a=ref(0)</span></span>
<span class="line"><span>a.value++</span></span>
<span class="line"><span>console.log(a.value) //服务端和客户端输出的都是1，这是因为属性是隔离的</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果要服务端和客户端共享数据可以使用useState函数获取共享的状态</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>const a= useState(&quot;number&quot;,()=&gt;{</span></span>
<span class="line"><span>	return 0</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span>a.value++</span></span>
<span class="line"><span>console.log(a.value) //服务端输出是1，客户端输出是2</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期"><span>生命周期</span></a></h1><p>nuxt中有三种生命周期钩子， 首先是服务端的生命周期，这些函数都运行在服务端，但输出可能在服务端也可能在客户端 服务端的生命周期执行完毕后就是vue本身的生命周期了，在vue自身的生命周期中beforeCreated和created这两个生命周期函数可能运行在服务端也可能运行在客户端（因为是服务端渲染） 在nuxt中不存在keep-alive和dekeep-alive生命周期，因为是服务端渲染的所以不存在组件的缓存</p><p>![[Pasted image 20250522113533.png]] ![[Pasted image 20250522113747.png]]</p>`,48)]))}const r=e(l,[["render",d]]),c=JSON.parse('{"path":"/front/vue/7/","title":"7 Nuxt","lang":"zh-CN","frontmatter":{"title":"7 Nuxt","createTime":"2025/06/10 18:17:50","permalink":"/front/vue/7/"},"readingTime":{"minutes":4.37,"words":1312},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/vue/7 Nuxt.md","headers":[]}');export{r as comp,c as data};
